import{_ as t,o as a,c as o,ae as i}from"./chunks/framework.B6gjLfeO.js";const v=JSON.parse('{"title":"Add and Manage Test Devices","description":"","frontmatter":{"title":"Add and Manage Test Devices","slug":"add-test-devices"},"headers":[],"relativePath":"account-hub/add-test-devices.md","filePath":"account-hub/add-test-devices.md"}'),s={name:"account-hub/add-test-devices.md"};function r(n,e,d,c,l,u){return a(),o("div",null,[...e[0]||(e[0]=[i('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>To easily test your campaign setup, we recommend you first add a test device to your Branch account. Doing so tells Branch servers that resulting conversions from said device are for testing purposes only; i.e. these conversions will not be considered normal traffic and therefore not be treated as such.</p><p>As Branch only allows one install event per unique device to ever be measured and stored, if you don&#39;t first add a test device, you&#39;ll only be able to test the install conversion event once ever.</p><div class="danger custom-block"><p class="custom-block-title">Warning</p><p>Please note that this article explains the <a href="./branch-dashboard-overview.html">legacy Branch experience</a> for adding and managing test devices, which is slated for deprecation.</p><p>In the <a href="./new-branch-overview.html">new version of Branch</a>, attribution windows are configured under <strong>Testing &amp; Monitoring</strong> &gt; <a href="./add-and-manage-test-devices-new.html"><strong>Add and Manage Test Devices</strong></a>.</p></div><h2 id="supported-device-ids" tabindex="-1">Supported device IDs <a class="header-anchor" href="#supported-device-ids" aria-label="Permalink to &quot;Supported device IDs&quot;">​</a></h2><p>To identify your device as a test device within Branch, we require you to provide one of the following device IDs:</p><ul><li>Android: Google Advertising ID (GAID)</li><li>iOS: Identifier for Advertisers (IDFA)</li></ul><div class="info custom-block"><p class="custom-block-title">Use Branch&#39;s Device ID Finder App</p><p>If you don&#39;t know how to access your device&#39;s IDs, you can use Branch&#39;s <strong>Device ID Finder</strong> app to easily see your device&#39;s ID.</p><ul><li>Get the <a href="https://play.google.com/store/apps/details?id=io.branch.deviceid" target="_blank" rel="noreferrer">Android App</a></li><li>Get the <a href="https://apps.apple.com/us/app/branch-device-id-finder/id1477763736" target="_blank" rel="noreferrer">iOS App</a></li></ul></div><h2 id="add-your-test-device" tabindex="-1">Add your test device <a class="header-anchor" href="#add-your-test-device" aria-label="Permalink to &quot;Add your test device&quot;">​</a></h2><p>To ensure you can use your device to test:</p><div class="info custom-block"><p class="custom-block-title">Keep In Mind...</p><ul><li>You can add up to 50 test devices per app in your Branch account.</li><li>Any user can add a device for testing; however, you must have Edit access to remove a test device.</li><li>The test device is specific to the app you add it under. If you use it to test other apps, Branch will treat it like live traffic and it will be attributed and used for downstream analytics.</li><li>These test devices work in both the live and test environment. You only need to add it once.</li></ul></div><ol><li>In the left-hand navigation, under <strong>Configure</strong>, select the <a href="https://dashboard.branch.io/test-devices" target="_blank" rel="noreferrer">Test Devices</a> page.</li><li>Select the <strong>Add Device</strong> button.</li><li>In the Add Device modal, provide the following:<br> a. <strong>Device Name</strong><br> b. <strong>Device ID</strong><br> c. <strong>Device Platform</strong></li><li>Select <strong>Add Device</strong>.</li></ol><h2 id="reset-your-test-device-data" tabindex="-1">Reset your test device data <a class="header-anchor" href="#reset-your-test-device-data" aria-label="Permalink to &quot;Reset your test device data&quot;">​</a></h2><p>If you need to test the install event more than once, you need to reset your test device data after each install attempt. Not doing so results in the next install attempt being marked as <code>reinstall</code>.</p><p>To reset your test device data:</p><ol><li>On the <a href="https://dashboard.branch.io/test-devices" target="_blank" rel="noreferrer">Test Devices</a> page, find the test device you want to reset and select the <code>...</code> button.</li><li>Select <strong>Reset Device Data</strong>.</li><li>In the pop-up modal, select <strong>Yes, Reset</strong>.</li></ol>',16)])])}const p=t(s,[["render",r]]);export{v as __pageData,p as default};
